import{_ as o,o as r,c as t,ag as i}from"./chunks/framework.CMYkYJvz.js";const h=JSON.parse('{"title":"Rule Priority","description":"Rule conflict and priority handling.","frontmatter":{"title":"Rule Priority","description":"Rule conflict and priority handling.","editLink":false},"headers":[],"relativePath":"en/reference/rules/rule-priority.md","filePath":"en/reference/rules/rule-priority.md"}'),s={name:"en/reference/rules/rule-priority.md"};function c(a,e,l,d,n,u){return r(),t("div",null,[...e[0]||(e[0]=[i(`<blockquote><p>This page is automatically synced from <code>docs-en/rules/rule-priority.md</code>. Language: <strong>English</strong> | <a href="./../../../reference/rules/rule-priority">中文</a></p></blockquote><h1 id="rule-priority-and-execution-order" tabindex="-1">Rule Priority and Execution Order <a class="header-anchor" href="#rule-priority-and-execution-order" aria-label="Permalink to &quot;Rule Priority and Execution Order&quot;">​</a></h1><p>Bifrost rule execution follows two principles.</p><ol><li>Routing rules are exclusive: the first matched routing rule wins. Among forwarding targets, <code>host</code>-family operations (<code>host</code>/<code>xhost</code>/<code>http</code>/<code>https</code>/<code>ws</code>/<code>wss</code>) win over <code>proxy</code> by protocol precedence, regardless of file order.</li><li>Modification rules can merge: operations on different fields combine. For duplicate keys the behavior is protocol-specific (see below).</li></ol><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>www.example.com host://server1.local</span></span>
<span class="line"><span>www.example.com host://server2.local</span></span></code></pre></div><p>The request goes to <code>server1.local</code> because the first routing rule wins.</p><p>Duplicate-key merge semantics differ by protocol:</p><ul><li><code>reqHeaders</code> / <code>resHeaders</code>: <strong>first occurrence wins</strong> — a later rule with the same header key is ignored (e.g. <code>X-Custom=value1</code> then <code>X-Custom=value2</code> yields <code>value1</code>).</li><li><code>reqCookies</code> / <code>urlParams</code>: last occurrence wins for the same key.</li><li><code>reqBody</code> / <code>resBody</code> / <code>resCors</code>: last matching rule overwrites earlier ones.</li><li><code>statusCode</code>: single-match — the first matching rule applies and later <code>statusCode</code> rules are ignored.</li></ul><p>Note: the emitted order of merged <code>urlParams</code> is not guaranteed to follow definition order.</p>`,9)])])}const f=o(s,[["render",c]]);export{h as __pageData,f as default};
